// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.concurrent.TimeUnit;

import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

/** Correctness, warm-switch, hidden-class and bounded-cache coverage for runtime batch specialization. */
public class LmdbNativeSpecializationTest {

	@BeforeEach
	public void setUp() {
		System.setProperty(LmdbNativeSpecialization.ENABLED_PROPERTY, "true");
		System.setProperty(LmdbNativeSpecialization.THRESHOLD_ROWS_PROPERTY, "1");
		LmdbNativeSpecialization.resetForTests();
	}

	@AfterEach
	public void tearDown() {
		System.clearProperty(LmdbNativeSpecialization.ENABLED_PROPERTY);
		System.clearProperty(LmdbNativeSpecialization.THRESHOLD_ROWS_PROPERTY);
		System.clearProperty(LmdbNativeSpecialization.MAX_ENTRIES_PROPERTY);
		System.clearProperty(LmdbNativeSpecialization.MAX_BYTES_PROPERTY);
	}

	@Test
	public void generatedHiddenKernelMatchesInterpreterExactly() throws Exception {
		RowState interpretedRow = row(3);
		RowState specializedRow = row(3);
		NativeBooleanFilter evenMiddleSlot = candidate -> (candidate.slots[1] & 1L) == 0L;
		NativeBatch interpreted = batch(3, 12, 0L);
		NativeBatch specialized = batch(3, 12, 0L);

		int expected = LmdbNativeSpecialization.interpretFilter(interpreted, interpretedRow, evenMiddleSlot);
		assertThat(LmdbNativeSpecialization.filterKernel(3, 1L)).isNull();
		NativeBatchFilterKernel kernel = LmdbNativeSpecialization.awaitFilterKernel(3, 5, TimeUnit.SECONDS);

		assertThat(kernel).isNotNull();
		assertThat(kernel.getClass().isHidden()).isTrue();
		assertThat(kernel.apply(specialized, specializedRow, evenMiddleSlot)).isEqualTo(expected);
		assertThat(Arrays.copyOf(specialized.selection, expected))
				.isEqualTo(Arrays.copyOf(interpreted.selection, expected));
		assertThat(specializedRow.slots).isEqualTo(interpretedRow.slots);
		assertThat(LmdbNativeSpecialization.filterKernel(3, 1L)).isSameAs(kernel);
		assertThat(LmdbNativeSpecialization.COMPILATIONS.get()).isOne();
		assertThat(LmdbNativeSpecialization.CACHE_HITS.get()).isOne();
		assertThat(LmdbNativeSpecialization.GENERATED_BYTES.get()).isPositive();
	}

	@Test
	public void filterBatchCursorStartsColdThenSwitchesAtBatchBoundary() throws Exception {
		RowState row = row(3);
		NativeBooleanFilter evenMiddleSlot = candidate -> (candidate.slots[1] & 1L) == 0L;
		NativeBatch output = new NativeBatch(3, 8);
		try (FilterBatchCursor cursor = new FilterBatchCursor(new TwoPageBatchCursor(), evenMiddleSlot, row)) {
			assertThat(cursor.fill(output)).isEqualTo(4);
			assertThat(LmdbNativeSpecialization.INTERPRETER_ROWS.get()).isEqualTo(8L);
			assertThat(LmdbNativeSpecialization.awaitFilterKernel(3, 5, TimeUnit.SECONDS)).isNotNull();

			assertThat(cursor.fill(output)).isEqualTo(4);
			assertThat(LmdbNativeSpecialization.SPECIALIZED_ROWS.get()).isEqualTo(8L);
			assertThat(cursor.fill(output)).isZero();
		}
	}

	@Test
	public void lruEntryAndByteCapsKeepFallbackBounded() throws Exception {
		System.setProperty(LmdbNativeSpecialization.MAX_ENTRIES_PROPERTY, "1");
		LmdbNativeSpecialization.filterKernel(2, 1L);
		NativeBatchFilterKernel first = LmdbNativeSpecialization.awaitFilterKernel(2, 5, TimeUnit.SECONDS);
		LmdbNativeSpecialization.filterKernel(4, 1L);
		NativeBatchFilterKernel second = LmdbNativeSpecialization.awaitFilterKernel(4, 5, TimeUnit.SECONDS);
		assertThat(first).isNotNull();
		assertThat(second).isNotNull();
		assertThat(LmdbNativeSpecialization.EVICTIONS.get()).isOne();

		LmdbNativeSpecialization.resetForTests();
		System.setProperty(LmdbNativeSpecialization.MAX_BYTES_PROPERTY, "1");
		LmdbNativeSpecialization.filterKernel(3, 1L);
		assertThat(LmdbNativeSpecialization.awaitFilterKernel(3, 5, TimeUnit.SECONDS)).isNull();
		assertThat(LmdbNativeSpecialization.BYTE_REJECTIONS.get()).isOne();
		assertThat(LmdbNativeSpecialization.COMPILE_FAILURES.get()).isZero();
	}

	@Test
	public void disabledAndColdFragmentsStayOnInterpreter() {
		System.setProperty(LmdbNativeSpecialization.ENABLED_PROPERTY, "false");
		NativeBatch batch = batch(2, 6, 0L);
		assertThat(LmdbNativeSpecialization.applyFilter(batch, row(2), candidate -> true, Long.MAX_VALUE))
				.isEqualTo(6);
		assertThat(LmdbNativeSpecialization.INTERPRETER_ROWS.get()).isEqualTo(6L);
		assertThat(LmdbNativeSpecialization.COMPILATIONS.get()).isZero();
	}

	private static RowState row(int slots) {
		java.util.LinkedHashMap<String, Integer> names = new java.util.LinkedHashMap<>();
		for (int i = 0; i < slots; i++) {
			names.put("slot" + i, i);
		}
		NativeSlotLayout layout = new NativeSlotLayout(Map.copyOf(names), null);
		layout.freeze(List.copyOf(names.keySet()));
		return new RowState(null, layout, EmptyBindingSet.getInstance());
	}

	private static NativeBatch batch(int slots, int rows, long base) {
		NativeBatch batch = new NativeBatch(slots, rows);
		for (int row = 0; row < rows; row++) {
			for (int slot = 0; slot < slots; slot++) {
				batch.set(slot, row, base + slot * 1_000L + row);
			}
		}
		batch.finishRows(rows);
		return batch;
	}

	private static final class TwoPageBatchCursor implements BatchCursor {
		int page;

		@Override
		public int fill(NativeBatch target) {
			if (page == 2) {
				target.clear();
				return 0;
			}
			long base = page++ * 100L;
			for (int row = 0; row < target.capacity; row++) {
				for (int slot = 0; slot < target.slotCount; slot++) {
					target.set(slot, row, base + slot * 1_000L + row);
				}
			}
			target.finishRows(target.capacity);
			return target.capacity;
		}

		@Override
		public void close() {
			page = 2;
		}
	}
}
